(top-rated swimmers refers to swimmers with the highest rating value in each event); 
(coach refers to the user associated with the swimmer as a coach); 
(performance metrics are values that measure a swimmer's performance in an event)

sql:
SELECT first_name, last_name
FROM swimmers
WHERE is_active = 1;

SELECT COUNT(*) AS active_swimmers_count
FROM swimmers
WHERE is_active = 1 AND team_id = 1;

SELECT first_name || ' ' || last_name AS full_name
FROM swimmers
ORDER BY full_name;
